import CountDown from "~/components/public/countDown";
import { client } from "@/utils/type";
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [
        {
          rel: "icon",
          type: "image/x-icon",
          href: this.$store.getters.favicon,
        },
      ],
    };
  },
  components: {
    CountDown,
  },
  async asyncData({ query, $get }) {
    const { data } = await $get("order/detail", {
      params: {
        id: query.id,
      },
    });
    return { order: data };
  },
  data() {
    return {
      showWxpay: false,
      showAlipay: false,
      payWayArr: [],
      payInfo: {},
      cancelTime: 0,
      alipayHtml: "",
    };
  },
  created() {
    this.id = this.$route.query.id;
    this.getPayway()
  },
  beforeDestroy() {
    clearInterval(this.timer);
  },
  methods: {
    async getPayway() {
      const { code, data} = await this.$get('payment/payway', {params: { from: 'order', order_id: this.id }})
      if(code == 1) {
        this.payWayArr = data.pay
        if(!this.payWayArr.length) this.$message({
          message: "请联系管理员配置支付方式",
          type: "error",
        });
      }
    },
    async orderPay(payWay) {
      const { data, code, msg } = await this.$post("payment/pcPrepay", {
        order_id: this.id,
        pay_way: payWay,
        order_source: client,
      });
      if (code == 1) {
        this.payInfo = data;
        this.showWxpay = true;
        this.createTimer();
      } else if (code == 20001) {
        let divForm = document.getElementsByTagName("divform");
        if (divForm.length) {
          document.body.removeChild(divForm[0]);
        }
        const div = document.createElement("divform");
        div.innerHTML = data.data; // data就是接口返回的form 表单字符串
        document.body.appendChild(div);
        document.forms[0].submit();
      } else if (code == 10001) {
        this.$message({
          message: msg,
          type: "success",
        });
        this.getOrder();
      }
    },
    clearTimer() {
      clearInterval(this.timer);
    },
    createTimer() {
      if (this.timer) clearInterval(this.timer);
      this.timer = setInterval(() => {
        this.getOrder();
      }, 2000);
    },
    async getOrder() {
      const { data, code, msg } = await this.$get("order/detail", {
        params: {
          id: this.id,
        },
      });
      if (code == 1) {
        this.order = data;
        if (data.pay_status == 1) {
          clearInterval(this.timer);
          this.showWxpay = false;
        }
      }
    },
  },
  computed: {
    getOrderStatus() {
      return (status) => {
        let text = "";
        switch (status) {
          case 0:
            text = "待支付";
            break;
          case 1:
            text = "待发货";
            break;
          case 2:
            text = "待收货";
            break;
          case 3:
            text = "已完成";
            break;
          case 4:
            text = "订单已关闭";
            break;
        }
        return text;
      };
    },
    getCancelTime() {
      return (time) => time - Date.now() / 1000;
    },
  },
};
